class AwsS3SigV4Uploader {
  AwsS3SigV4Uploader({
    required this.accessKeyId,
    required this.secretAccessKey,
    required this.region,
  });

  final String accessKeyId;
  final String secretAccessKey;
  final String region;

  Future<String> putObject({
    required String bucket,
    required String key,
    required Uint8List bytes,
    required String contentType,
    required bool publicRead,
  }) async {
    if (accessKeyId.isEmpty || secretAccessKey.isEmpty) {
      throw StateError('AWS credentials missing. Provide via --dart-define.');
    }
    if (bucket.isEmpty) {
      throw StateError('S3 bucket missing. Provide via --dart-define.');
    }

    final host = _virtualHostedStyleHost(bucket, region);
    final uri = Uri.https(host, '/${_uriEncodePath(key)}');

    final now = DateTime.now().toUtc();
    final amzDate = _formatAmzDate(now);
    final dateStamp = _formatDateStamp(now);
    final payloadHash = sha256.convert(bytes).toString();

    final headers = <String, String>{
      'host': host,
      'x-amz-content-sha256': payloadHash,
      'x-amz-date': amzDate,
      'content-type': contentType,
    };

    if (publicRead) {
      headers['x-amz-acl'] = 'public-read';
    }

    final signedHeaders = headers.keys.map((k) => k.toLowerCase()).toList()..sort();
    final canonicalHeaders = signedHeaders.map((k) => '$k:${_trimAll(headers[k] ?? '')}\n').join();
    final signedHeadersStr = signedHeaders.join(';');

    final canonicalRequest = [
      'PUT',
      '/${_uriEncodePath(key)}',
      '',
      canonicalHeaders,
      signedHeadersStr,
      payloadHash,
    ].join('\n');

    final algorithm = 'AWS4-HMAC-SHA256';
    final credentialScope = '$dateStamp/$region/s3/aws4_request';
    final stringToSign = [
      algorithm,
      amzDate,
      credentialScope,
      sha256.convert(utf8.encode(canonicalRequest)).toString(),
    ].join('\n');

    final signingKey = _getSignatureKey(secretAccessKey, dateStamp, region, 's3');
    final signature = _hmacSha256Hex(signingKey, utf8.encode(stringToSign));

    final authorization =
        '$algorithm Credential=$accessKeyId/$credentialScope, SignedHeaders=$signedHeadersStr, Signature=$signature';

    final reqHeaders = <String, String>{
      ...headers,
      'Authorization': authorization,
    };

    final resp = await http.put(uri, headers: reqHeaders, body: bytes);
    if (resp.statusCode < 200 || resp.statusCode >= 300) {
      throw HttpException(
        'S3 PUT failed: ${resp.statusCode}\n${resp.body.isNotEmpty ? resp.body : resp.reasonPhrase}',
        uri: uri,
      );
    }

    return uri.toString();
  }

  String _virtualHostedStyleHost(String bucket, String region) {
    if (region == 'us-east-1') return '$bucket.s3.amazonaws.com';
    return '$bucket.s3.$region.amazonaws.com';
  }

  List<int> _getSignatureKey(String key, String dateStamp, String regionName, String serviceName) {
    final kDate = _hmacSha256(utf8.encode('AWS4$key'), utf8.encode(dateStamp));
    final kRegion = _hmacSha256(kDate, utf8.encode(regionName));
    final kService = _hmacSha256(kRegion, utf8.encode(serviceName));
    final kSigning = _hmacSha256(kService, utf8.encode('aws4_request'));
    return kSigning;
  }

  List<int> _hmacSha256(List<int> key, List<int> message) {
    final h = Hmac(sha256, key);
    return h.convert(message).bytes;
  }

  String _hmacSha256Hex(List<int> key, List<int> message) {
    final h = Hmac(sha256, key);
    return h.convert(message).toString();
  }

  String _formatAmzDate(DateTime dt) {
    String two(int v) => v.toString().padLeft(2, '0');
    return '${dt.year}${two(dt.month)}${two(dt.day)}T${two(dt.hour)}${two(dt.minute)}${two(dt.second)}Z';
  }

  String _formatDateStamp(DateTime dt) {
    String two(int v) => v.toString().padLeft(2, '0');
    return '${dt.year}${two(dt.month)}${two(dt.day)}';
  }

  String _trimAll(String s) => s.replaceAll(RegExp(r'\s+'), ' ').trim();

  String _uriEncodePath(String key) {
    return key.split('/').map((seg) => Uri.encodeComponent(seg)).join('/');
  }
}

class GoogleCloudVision {
  GoogleCloudVision({required this.apiKey});
  final String apiKey;

  Future<Map<String, dynamic>> analyze(Uint8List bytes) async {
    if (apiKey.isEmpty) {
      throw StateError('Google Cloud Vision API key missing. Provide via --dart-define.');
    }

    final endpoint = Uri.parse('https://vision.googleapis.com/v1/images:annotate?key=$apiKey');
    final content = base64Encode(bytes);

    final body = {
      'requests': [
        {
          'image': {'content': content},
          'features': [
            {'type': 'LABEL_DETECTION', 'maxResults': 10},
            {'type': 'TEXT_DETECTION', 'maxResults': 10},
            {'type': 'FACE_DETECTION', 'maxResults': 5},
            {'type': 'OBJECT_LOCALIZATION', 'maxResults': 10},
            {'type': 'SAFE_SEARCH_DETECTION', 'maxResults': 1},
          ],
        }
      ],
    };

    final resp = await http.post(
      endpoint,
      headers: {'content-type': 'application/json'},
      body: jsonEncode(body),
    );

    if (resp.statusCode < 200 || resp.statusCode >= 300) {
      throw HttpException('Vision API failed: ${resp.statusCode}\n${resp.body}');
    }

    final decoded = jsonDecode(resp.body);
    if (decoded is! Map<String, dynamic>) {
      throw StateError('Unexpected Vision response.');
    }

    final responses = decoded['responses'];
    if (responses is List && responses.isNotEmpty && responses.first is Map<String, dynamic>) {
      final first = responses.first as Map<String, dynamic>;
      if (first.containsKey('error')) {
        throw StateError('Vision error: ${jsonEncode(first['error'])}');
      }
      return first;
    }

    return {'raw': decoded};
  }
}

