    final faces = (result['faceAnnotations'] as List?)?.cast<Map>() ?? const [];
    final safe = result['safeSearchAnnotation'] as Map?;

    return Card(
      child: Padding(
        padding: const EdgeInsets.all(12),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Text('Vision Result', style: Theme.of(context).textTheme.titleMedium),
            const SizedBox(height: 12),
