              Text('Labels', style: Theme.of(context).textTheme.titleSmall),
              const SizedBox(height: 6),
              Wrap(
                spacing: 8,
                runSpacing: 8,
                children: labels.take(10).map((m) {
                  final desc = (m['description'] ?? '').toString();
                  final score = (m['score'] is num) ? (m['score'] as num).toDouble() : null;
                  return Chip(label: Text(score != null ? '$desc (${(score * 100).toStringAsFixed(0)}%)' : desc));
                }).toList(),
              ),
              const SizedBox(height: 12),
            ],
            if (objects.isNotEmpty) ...[
              Text('Objects', style: Theme.of(context).textTheme.titleSmall),
              const SizedBox(height: 6),
              Wrap(
                spacing: 8,
                runSpacing: 8,
                children: objects.take(10).map((m) {
                  final name = (m['name'] ?? '').toString();
                  final score = (m['score'] is num) ? (m['score'] as num).toDouble() : null;
                  return Chip(label: Text(score != null ? '$name (${(score * 100).toStringAsFixed(0)}%)' : name));
                }).toList(),
              ),
              const SizedBox(height: 12),
            ],
            if (faces.isNotEmpty) ...[
              Text('Faces', style: Theme.of(context).textTheme.titleSmall),
              const SizedBox(height: 6),
              Text('Detected faces: ${faces.length}'),
              const SizedBox(height: 12),
            ],
            if (safe != null) ...[
              Text('SafeSearch', style: Theme.of(context).textTheme.titleSmall),
              const SizedBox(height: 6),
              Text(_formatSafeSearch(safe)),
              const SizedBox(height: 12),
            ],
            if (text != null && text.trim().isNotEmpty) ...[
              Text('Text', style: Theme.of(context).textTheme.titleSmall),
              const SizedBox(height: 6),
              Container(
                width: double.infinity,
                padding: const EdgeInsets.all(10),
                decoration: BoxDecoration(
                  color: Theme.of(context).colorScheme.surfaceContainerHighest,
                  borderRadius: BorderRadius.circular(8),
                ),
                child: SelectableText(text),
              ),
            ],
            if (labels.isEmpty && objects.isEmpty && faces.isEmpty && safe == null && (text == null || text.trim().isEmpty))
              const Text('No structured annotations found.'),
          ],
        ),
      ),
    );
  }

  String _formatSafeSearch(Map safe) {
    final adult = safe['adult']?.toString();
    final violence = safe['violence']?.toString();
    final racy = safe['racy']?.toString();
    final medical = safe['medical']?.toString();
    final spoof = safe['spoof']?.toString();
    return 'adult=$adult, violence=$violence, racy=$racy, medical=$medical, spoof=$spoof';
  }
}

